// Package platform defines the Extractor interface for application platform
// scrapers and the canonical set of platform key constants.
package platform

import "context"

// Browser is satisfied by scraper.Browser (defined in kapow-j2l.1).
type Browser interface {
	Navigate(ctx context.Context, url string) error
	EvalStrings(ctx context.Context, jsExpr string) ([]string, error)
}

// Extractor scrapes a single application platform's member-institution list.
type Extractor interface {
	// Key returns the enum value stored in JSONB (e.g. "Common", "CBCA").
	Key() string
	// Label returns a human-readable label (e.g. "Common App").
	Label() string
	// Extract navigates the platform website and returns institution names.
	Extract(ctx context.Context, browser Browser) ([]string, error)
}

// Platform key constants — one per supported application platform.
const (
	KeyCommon        = "Common"
	KeyCoalition     = "Coalition"
	KeyCBCA          = "CBCA"
	KeyQuestBridge   = "QuestBridge"
	KeyApplyTexas    = "ApplyTexas"
	KeyApplySUNY     = "ApplySUNY"
	KeyUCApplication = "UCApplication"
	KeyCalStateApply = "CalStateApply"
	KeyUWSystem      = "UWSystem"
	KeyApplyIdaho    = "ApplyIdaho"
	KeyGAFutures     = "GAFutures"
	KeyCFNC          = "CFNC"
	KeyFloridaSUS    = "FloridaSUS"
)

// AllKeys returns every platform key constant. Useful for validation and tests.
func AllKeys() []string {
	return []string{
		KeyCommon,
		KeyCoalition,
		KeyCBCA,
		KeyQuestBridge,
		KeyApplyTexas,
		KeyApplySUNY,
		KeyUCApplication,
		KeyCalStateApply,
		KeyUWSystem,
		KeyApplyIdaho,
		KeyGAFutures,
		KeyCFNC,
		KeyFloridaSUS,
	}
}

// All returns all registered Extractors. Initially empty; extractors are added
// in subsequent issues as each platform scraper is implemented.
func All() []Extractor {
	return nil
}
